using System.Threading.Tasks;
using System.Windows.Forms;

namespace WindowsFormsApp1
{
    public partial class _FrmConfiguration: Form
    {
        public _FrmConfiguration()
        {
            InitializeComponent();
            Configuration config = new Configuration();
            propertyGrid1.SelectedObject = config;
            GlobalValues.FlagServoSet = true;
        }

        private void button3_Click(object sender, EventArgs e)
        {
            var config = propertyGrid1.SelectedObject as Configuration;
            config?.Apply();
            GlobalValues.SaveChannelSettingsToIni();
            PLCData.ServoSet();
            MessageBox.Show("환경 설정이 적용되었습니다!");
        }

        private void button2_Click(object sender, EventArgs e)
        {
            GlobalValues.FlagServoSet = false;
            this.Close();
        }
    }
