        ini.WriteValue("System", "LoadLimit", LoadLimit.ToString());
        ini.WriteValue("System", "LoadLengthLimit", LoadLengthLimit.ToString());

        ini.WriteValue("System", "SpecLoadSpecMin", SpecLoadSpecMin.ToString());
        ini.WriteValue("System", "SpecLoadSpecMax", SpecLoadSpecMax.ToString());

        ini.WriteValue("System", "BoltLimit", BoltLimit.ToString());
        ini.WriteValue("System", "BoltLenSpecMin", BoltLenSpecMin.ToString());
        ini.WriteValue("System", "BoltLenSpecMax", BoltLenSpecMax.ToString());

