        ini.WriteValue("System", "LvdtOffSet2", LvdtOffset2.ToString());

        ini.WriteValue("System", "PassDistance", PassDistance.ToString());
        ini.WriteValue("System", "PassDistanceTol", PassDistanceTol.ToString());

    }

}

