private void PortOpen(SerialPort tControl, string tPortNumber, int tBaudRate, string portLabelName)
{
    try
    {
        if (tControl.IsOpen)
            tControl.Close();

        tControl.PortName = tPortNumber;
        tControl.BaudRate = tBaudRate;
        tControl.DataBits = 8;
        tControl.Open();
        Logger.Log($"{portLabelName} ({tControl.PortName}): OK");

    }
    catch (Exception)
    {
        Logger.Log($"{portLabelName} ({tControl.PortName}): NG");

    }

}
public void InsertData()
{
    try
    {
        using (var conn = new OleDbConnection(GlobalValues.gConString_Record))
        {
            conn.Open();

            string query = @"INSERT INTO Table1 
                             (WorkDate, WorkStartTime,WorkEndTime,MeasureValue,Decision)                                    
                             VALUES (@1, @2, @3, @4, @5)";

            using (var cmd = new OleDbCommand(query, conn))
            {
                // 날짜 및 시간
                cmd.Parameters.AddWithValue("@1", System.DateTime.Now.ToString("yyyy-MM-dd"));
                cmd.Parameters.AddWithValue("@2", tmpStartTime);
                cmd.Parameters.AddWithValue("@3", System.DateTime.Now.ToString("HH:mm:ss"));
                // 사용자 입력 값

