1087→        private void SerialLoadCell_DataReceived(object sender, SerialDataReceivedEventArgs e)
1088→        {
1089→            try
1090→            {
1091→                while (SerialLoadCell.BytesToRead > 0)
1092→                {
1093→                    int b = SerialLoadCell.ReadByte();
1094→                    char ch = (char)b;
1095→
1096→                    // STX (0x02)가 들어오면 버퍼 새로 시작
1097→                    if (b == 0x02)
1098→                    {
1099→                        LoadCellreceiveBuffer.Clear();
1100→                        LoadCellreceiveBuffer.Append(ch);
1101→                        continue;
1102→                    }
1103→
1104→                    LoadCellreceiveBuffer.Append(ch);
1105→
1106→                    // ETX (0x03) 도착 시 한 패킷 완성
1107→                    if (b == 0x03)
1108→                    {
1109→                        string packet = LoadCellreceiveBuffer.ToString();
1110→                        LoadCellreceiveBuffer.Clear();
1111→
1112→                        // 패킷 유효성 검사
1113→                        if (packet.StartsWith(((char)0x02).ToString()) && packet.EndsWith(((char)0x03).ToString()))
1114→                        {
1115→                            ParseWeightPacket(packet);
1116→                        }
1117→                        else
1118→                        {
1119→                            Logger.Log($"[LoadCell 무시됨] 잘못된 형식: {packet}");
1120→                        }
1121→                    }
1122→                }
