            // Count 영역 스타일
            lbOkCount.BackColor = lightMint;
            lbNGCount.BackColor = lightMint;
            lbTotalCount.BackColor = lightMint;
            lbOkCount.ForeColor = System.Drawing.Color.Black;
            lbNGCount.ForeColor = System.Drawing.Color.Black;
