        private void SerialLoadCell_DataReceived(object sender, SerialDataReceivedEventArgs e)
        {
            try
            {
                while (SerialLoadCell.BytesToRead > 0)
                {
                    int b = SerialLoadCell.ReadByte();
                    char ch = (char)b;

                    // STX (0x02)가 들어오면 버퍼 새로 시작
                    if (b == 0x02)
                    {
                        LoadCellreceiveBuffer.Clear();
                        LoadCellreceiveBuffer.Append(ch);
                        continue;
                    }

                    LoadCellreceiveBuffer.Append(ch);

                    // ETX (0x03) 도착 시 한 패킷 완성
                    if (b == 0x03)
                    {
                        string packet = LoadCellreceiveBuffer.ToString();
                        LoadCellreceiveBuffer.Clear();

                        // 패킷 유효성 검사
                        if (packet.StartsWith(((char)0x02).ToString()) && packet.EndsWith(((char)0x03).ToString()))
                        {
                            ParseWeightPacket(packet);
                        }
                        else
                        {
                            Logger.Log($"[LoadCell 무시됨] 잘못된 형식: {packet}");
                        }
                    }
                }
            }
            catch (Exception ex)
            {
                Logger.Log("[LoadCell 수신 오류] " + ex.Message);
            }
        }

        // 게이지 수신: "0,-2.233, +40000,+0000 0000000\r\n" 형식
        private void SerialGauge_DataReceived(object sender, SerialDataReceivedEventArgs e)
        {
            try
            {
                while (SerialGauge.BytesToRead > 0)
                {
                    int b = SerialGauge.ReadByte();
                    char ch = (char)b;

                    if (ch == '\r' || ch == '\n')
                    {
                        string line = GaugeReceiveBuffer.ToString().Trim();
                        GaugeReceiveBuffer.Clear();

                        if (string.IsNullOrEmpty(line)) continue;

                        // "0,-2.233, +40000,+0000 0000000" → 두 번째 필드 추출
                        string[] fields = line.Split(',');
                        if (fields.Length >= 2)
                        {
                            string valueStr = fields[1].Trim();
                            if (double.TryParse(valueStr, NumberStyles.Float, CultureInfo.InvariantCulture, out double value))
                            {
                                ValueGauge = value;
                                lbGauge.Invoke((MethodInvoker)(() =>
                                {
                                    lbGauge.Text = ValueGauge.ToString("F3");
                                }));
                            }
                        }
                    }
                    else
                    {
                        GaugeReceiveBuffer.Append(ch);
                    }
                }
            }
            catch (Exception ex)
            {
                Logger.Log("[Gauge 수신 오류] " + ex.Message);
            }
        }

        private void ParseWeightPacket(string packet)
        {
            try
            {
                int stx = packet.IndexOf((char)2); // STX (0x02)
                int etx = packet.IndexOf((char)3); // ETX (0x03)

                //Logger.Log($"[stx:{stx}][etx:{etx}]");

                // STX/ETX가 모두 존재할 때만 처리
                if (stx >= 0 && etx > stx)
                {
                    string data = packet.Substring(stx + 1, etx - stx - 1); // "1+32.567" 등
                    //Logger.Log($"[data:{data}]");

                    if (data.Length >= 3 && data[0] == '1') // ID 체크
                    {
                        string valueStr = data.Substring(1).Replace(" ", ""); // "+0.00" ← 공백 제거

                        if (double.TryParse(valueStr, NumberStyles.Float, CultureInfo.InvariantCulture, out double value))
                        {
                            ValueLoadCell = value;

                            lbLoadCell.Invoke((MethodInvoker)(() =>
                            {
                                lbLoadCell.Text = ValueLoadCell.ToString("F3");
                            }));
                        }
                        else
                        {
                            Logger.Log($"[파싱 실패] 잘못된 숫자 형식: '{valueStr}'");
                        }
                    }
                    else
                    {
                        Logger.Log($"[무시됨] ID가 '1'이 아님 or 데이터 길이 부족: '{data}'");
                    }
                }
                else
                {
                    Logger.Log($"[무시됨] STX 또는 ETX가 없음. 원본: {packet}");
                }
            }
            catch (Exception ex)
            {
                Logger.Log("[예외 발생] " + ex.Message);
                // 프로그램이 멈추지 않게 예외 먹고 로그만 남김
            }
        }

