        public void InsertMes_Bolt(string work_date, string work_start_time, string work_end_time,
                           string screwTq1, string screwLen1, string screwDec1, string screwErr1,
                           string screwTq2, string screwLen2, string screwDec2, string screwErr2,
                           bool ZeroMaster)
        {
            try
            {
                using (var conn = new OleDbConnection(GlobalValues.gConString_MES))
                {
                    conn.Open();

                    string query = @"
                    INSERT INTO MOTOR_ROTOR_SUB_ASSY_310_MSC
                    (
                        work_date,
                        work_start_time,
                        work_end_time,
                        mscrew_torque1,
                        mscrew_length1,
                        mscrew_decision1,
                        mscrew_error1,
                        mscrew_torque2,
                        mscrew_length2,
                        mscrew_decision2,
                        mscrew_error2,
                        zero_master
                    )
                    VALUES
                    (
                        ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?
                    )";

                    using (var cmd = new OleDbCommand(query, conn))
                    {
                        // 문자열 그대로
                        cmd.Parameters.AddWithValue("@p1", string.IsNullOrWhiteSpace(work_date) ? DBNull.Value : (object)work_date);
                        cmd.Parameters.AddWithValue("@p2", string.IsNullOrWhiteSpace(work_start_time) ? DBNull.Value : (object)work_start_time);
                        cmd.Parameters.AddWithValue("@p3", string.IsNullOrWhiteSpace(work_end_time) ? DBNull.Value : (object)work_end_time);

                        // decimal 변환
                        decimal tq1 = 0, len1 = 0, tq2 = 0, len2 = 0;
                        decimal.TryParse(screwTq1, out tq1);
                        decimal.TryParse(screwLen1, out len1);
                        decimal.TryParse(screwTq2, out tq2);
                        decimal.TryParse(screwLen2, out len2);

                        cmd.Parameters.AddWithValue("@p4", tq1);
                        cmd.Parameters.AddWithValue("@p5", len1);

                        // 문자열 그대로
                        cmd.Parameters.AddWithValue("@p6", string.IsNullOrWhiteSpace(screwDec1) ? DBNull.Value : (object)screwDec1);
                        cmd.Parameters.AddWithValue("@p7", string.IsNullOrWhiteSpace(screwErr1) ? DBNull.Value : (object)screwErr1);

                        // decimal 2
                        cmd.Parameters.AddWithValue("@p8", tq2);
                        cmd.Parameters.AddWithValue("@p9", len2);

                        // 문자열 그대로
                        cmd.Parameters.AddWithValue("@p10", string.IsNullOrWhiteSpace(screwDec2) ? DBNull.Value : (object)screwDec2);
                        cmd.Parameters.AddWithValue("@p11", string.IsNullOrWhiteSpace(screwErr2) ? DBNull.Value : (object)screwErr2);

