        PLCData.SetPlc(6010, GlobalValues.Servo1Pos3Spd);
        PLCData.SetPlc(6014, GlobalValues.Servo1Pos4Spd);
        PLCData.SetPlc(6018, GlobalValues.Servo1Pos5Spd);

        //2축 10000
