case 4.1:
    if (PLCData.PlcValueBit[14, 5] == true) // 6번 포지션 도착
    {
        PLCData.SetPlcBit(12, 5, false);
        Logger.Log("포지션 6번 도착 완료");
        LoadStopWatch.Restart();
        LotorAssembleStep = 4.2;
    }
    break;

case 4.2:
    if (LoadStopWatch.Elapsed.TotalSeconds > 0.5)
    {
        // 로드셀 리셋
        ResetLoadCell();
        Logger.Log("로드셀 초기화");
