            yColor: System.Drawing.Color.Red,
            lineWidth: 2.0f,
            lineStyle: System.Drawing.Drawing2D.DashStyle.Dash);

        // 판정 (최대 로드셀 값 기준)
        srcMeasureLoad.Text = maxLoadInPassRange.ToString("F2");
        Logger.Log($"[case 6.5] 판정: maxLoadInPassRange={maxLoadInPassRange:F3}, SpecMin={GlobalValues.SpecLoadSpecMin}, SpecMax={GlobalValues.SpecLoadSpecMax}");

        if (maxLoadInPassRange >= GlobalValues.SpecLoadSpecMin && maxLoadInPassRange <= GlobalValues.SpecLoadSpecMax)
