            lineStyle: System.Drawing.Drawing2D.DashStyle.Dash);

        PLCData.SetPlcBit(9, 1, true); // 1축 조그 CW(전진)
        Logger.Log("조그 전진 시작 (게이지 검사)");
        LotorAssembleStep = 5;
    }
    break;

case 5:
    // 부하 감지 대기 (그래프 아직 안그림)
    if (ValueLoadCell > 0.1)
    {
        loadStarted = true;
        gaugeStartValue = ValueGauge;
        Logger.Log($"부하 감지 - 그래프 시작, LoadCell={ValueLoadCell:F3}, Gauge={ValueGauge:F3}");
        LotorAssembleStep = 6;
    }
    // 부하 미감지 상태에서 게이지 0 도달 → 정지
    if (Math.Abs(ValueGauge) <= 0.05)
    {
        PLCData.SetPlcBit(9, 1, false);
        Logger.Log("게이지 0 도달 (부하 미감지) - 조그 정지");
        LotorAssembleStep = 6.5;
    }
    break;

case 6:
    // 그래프 그리기 + 모니터링
    {
        double gaugeX = ValueGauge - gaugeStartValue; // 시작점 대비 이동거리 (양수)
        timeList.Add(gaugeX);
        valueList.Add(ValueLoadCell);
        if (tmpMax < ValueLoadCell) { tmpMax = ValueLoadCell; }

        ClassZedGraph.DrawGraph(zedGraphControl1, ValueLoadCell, gaugeX);

        // 게이지 0 도달 → 조그 정지, 판정
        if (Math.Abs(ValueGauge) <= 0.05)
        {
            PLCData.SetPlcBit(9, 1, false);
            Logger.Log($"게이지 0 도달 - 조그 정지, 최대하중={tmpMax:F3}");
            LotorAssembleStep = 6.5;
        }
        // 하중이 스펙 MAX 초과 → 즉시 정지
        else if (ValueLoadCell > GlobalValues.SpecLoadSpecMax)
        {
            PLCData.SetPlcBit(9, 1, false);
            Logger.Log($"하중 초과 정지 - LoadCell={ValueLoadCell:F3} > Max={GlobalValues.SpecLoadSpecMax}");
            LotorAssembleStep = 6.5;
        }
    }
    break;

case 6.5:
    // 판정
    {
        srcMeasureLoad.Text = tmpMax.ToString("F2");
        Logger.Log($"판정: 최대하중={tmpMax:F3}, SpecMin={GlobalValues.SpecLoadSpecMin}, SpecMax={GlobalValues.SpecLoadSpecMax}");

        if (tmpMax >= GlobalValues.SpecLoadSpecMin && tmpMax <= GlobalValues.SpecLoadSpecMax)
        {
            srcDecideLoad.Text = "OK";
            srcDecideLoad.ForeColor = System.Drawing.Color.LightBlue;
            PlaySound("DINGDONG.wav");
            Logger.Log("판정 OK");
        }
        else
        {
            srcDecideLoad.Text = "NG";
            srcDecideLoad.ForeColor = System.Drawing.Color.OrangeRed;
            PlaySound("NG.wav");
            Logger.Log("판정 NG");
        }

        LotorEndTime = System.DateTime.Now.ToString("HH:mm:ss");
        InsertMes_Lotor(System.DateTime.Now.ToString("yyyy-MM-dd"), LotorStartTime, LotorEndTime,
                        srcMeasureLoad.Text, "", srcDecideLoad.Text, "", false);

        // 조그 속도 복원
        GlobalValues.Servo1JogSpd = savedJogSpd;
        LotorAssembleStep = 7;
    }
    break;

case 7:
    // 자동 모드 전환
    PLCData.SetPlcBit(9, 5, true);   // 1축 자동 ON
    PLCData.SetPlcBit(11, 5, true);  // 2축 자동 ON
    PLCData.SetPlcBit(9, 6, false);  // 1축 수동 OFF
    PLCData.SetPlcBit(11, 6, false); // 2축 수동 OFF
    Logger.Log("자동 모드 전환");
    tmrStopWatch.Restart();
    LotorAssembleStep = 7.1;
    break;

case 7.1:
    if (tmrStopWatch.ElapsedMilliseconds > 500)
    {
        PLCData.SetPlcBit(12, 0, true); // 1축 1번 포지션 이동 ON
        Logger.Log("1축 1번 포지션 이동 시작");
        LotorAssembleStep = 8;
    }
    break;

case 8:
    if (PLCData.PlcValueBit[14, 0] == true) // 도착 완료
    {
        PLCData.SetPlcBit(12, 0, false);
        Logger.Log("1축 1번 포지션 이동 완료");
        LotorAssembleStep = 8.1;
    }
    break;

case 8.1:
    if (srcDecideLoad.Text == "NG")
    {
        if (PLCData.PlcValueBit[0, 0] == true)
        {
            LotorAssembleStep = 4; // 재검사
        }
    }
    else
    {
        LotorAssembleStep = 9;
    }
    break;

case 9:
    if (PLCData.PlcValueBit[0, 4] == false) // 제품 제거
    {
        if (srcDecideLoad.Text == "OK")
            LotorAssembleStep = 10;
        else
            LotorAssembleStep = 0;
    }
    break;

case 10:
    GlobalValues.TotalCount++;
    GlobalValues.OkCount++;
    lbOkCount.Text = GlobalValues.OkCount.ToString();
    lbNGCount.Text = (GlobalValues.TotalCount - GlobalValues.OkCount).ToString();
    lbTotalCount.Text = GlobalValues.TotalCount.ToString();
    GlobalValues.SaveCounts();
    LotorAssembleStep = 0;
    break;

