        public void ReadD(int startAddress, int count)
        {
            string startAddressText = $"%DW{startAddress:D4}";
            string countHex = count.ToString("X2");
            string packet = $"{(char)5}00RSB07{startAddressText}{countHex}{(char)4}";
            SerialPlc.Write(packet);
        }
        public void WriteDbit(int startAddress, ushort[] data)
        {
            string startAddressText = $"%DW{startAddress:D4}";
            string countHex = data.Length.ToString("X2"); // 예: 32 → "20"

            // 데이터: 각 워드를 4자리 HEX로 연결
            StringBuilder hexBuilder = new StringBuilder();
            foreach (ushort word in data)
                hexBuilder.Append(word.ToString("X4"));

            // 전체 패킷 구성
            string packet = $"{(char)5}00WSB07{startAddressText}{countHex}{hexBuilder}{(char)4}";
            SerialPlc.Write(packet);
            //Logger.Log($"[WRITE 보냄] Addr:{startAddress} Words:{data.Length} Packet:{packet}");
        }
        public void WriteD(int startAddress, int count)
        {
            int[] values = PLCData.writePlcValue.Skip(startAddress).Take(count).ToArray();
            string hexData = string.Join("", values.Select(v => v.ToString("X4")));
            string startAddressText = $"%DW{startAddress:D4}";
            string countHex = count.ToString("X2");
            string packet = $"{(char)5}00WSB07{startAddressText}{countHex}{hexData}{(char)4}";
            SerialPlc.Write(packet);
        }
        public static ushort[] GetWriteWords()
        {
            ushort[] words = new ushort[32]; // D4000~D4031

            for (int w = 0; w < 32; w++)
            {
                ushort word = 0;
                for (int b = 0; b < 16; b++)
                {
                    if (PLCData.writePlcValueBit[w, b])
                        word |= (ushort)(1 << b);
                }
                words[w] = word;
            }

            return words;
        }
        private void StartPlcWorkThread()
        {
            plcWorkThread = new Thread(() =>
            {
                while (isRunning)
                {
                    if (SerialPlc.IsOpen && RequestReadyPlc)
                    {
                        RequestReadyPlc = false;
                        currentIsWrite = false;

                        if (rwStep == 0)
                        {
                            int cycleTime = (int)(System.DateTime.Now - cycleStartTime).TotalMilliseconds;
                            cycleStartTime = System.DateTime.Now;
                            LbCycle.Invoke((MethodInvoker)(() =>
                            {
                                LbCycle.Text = $"Cycle: {cycleTime} ms";
                            }));
                        }

                        switch (rwStep)
                        {
                            case 0:
                                currentRequestAddress = 4000;
                                ReadD(currentRequestAddress, 32);
                                break;

                            case 1:
                                ushort[] wordsToSend = GetWriteWords();
                                WriteDbit(4000, wordsToSend);
                                break;

                            case 2:
                                currentRequestAddress = 5000;
                                WriteD(currentRequestAddress, 32);
                                break;

                            case 3:
                                currentRequestAddress = 5000;
                                ReadD(currentRequestAddress, 32);
                                break;

                            case 4:
                                currentRequestAddress = 6000;
                                WriteD(currentRequestAddress, 32);
                                break;
                        }

                        // 순서 제어
                        if (GlobalValues.FlagServoSet)
                        {
                            rwStep = (rwStep + 1) % 5;
                        }
                        else
                        {
                            rwStep = (rwStep == 0) ? 1 : 0;
                        }
                    }

                    Thread.Sleep(1);
                }
            });

            plcWorkThread.IsBackground = true;
            plcWorkThread.Start();
        }
        private void StartPlcReceiveThread()
        {
            plcReceiveThread = new Thread(() =>
            {
                while (isRunning)
                {
                    try
                    {
                        if (SerialPlc.IsOpen && SerialPlc.BytesToRead > 0)
                        {
                            char ch = (char)SerialPlc.ReadChar();
                            receiveBuffer.Append(ch);

                            if (ch == (char)3) // ETX
                            {
                                string fullPacket = receiveBuffer.ToString();
                                receiveBuffer.Clear();
                                //Logger.Log($"[RECV] {(fullPacket)}");
                                ProcessPlcPacket(fullPacket);
                            }
                        }
                        else
                        {
                            Thread.Sleep(1);
                        }
                    }
                    catch (Exception ex)
                    {
                        Logger.Log("[에러] 수신 쓰레드: " + ex.Message);
                    }
                }
            });

            plcReceiveThread.IsBackground = true;
            plcReceiveThread.Start();
        }
        private void ProcessPlcPacket(string packet)
        {
            if (packet.Contains("00RSB"))
            {
                ParsePlcResponse(packet, currentRequestAddress);
            }
            else if (packet.Contains("00WSB"))
            {
                //Logger.Log($"[WRITE 응답] D{currentRequestAddress} 쓰기 완료 ✅");

                // 쓰기 성공 시 기준값 갱신
                for (int i = 0; i < 16; i++)
                {
                    lastWriteBuffer[currentRequestAddress + i] = PLCData.PlcValue[currentRequestAddress + i];
                }
            }

            RequestReadyPlc = true;
        }
        public static int Hex2Dec(string hex)
        {
            try
            {
                return Convert.ToInt32(hex, 16);  // VB의 &H 방식과 동일한 기능
            }
            catch
            {
                return 0;
