﻿using System;
using System.Collections.Generic;
using System.Linq;
using System.Text;
using System.Threading.Tasks;
using System.Windows.Forms;

public static class PLCData
{
    public static bool[,] PlcValueBit = new bool[32, 16];
    public static bool[,] writePlcValueBit = new bool[32, 16];
    public static void SetPlcBit(int dWord, int bitIndex, bool value)
    {
        int wordOffset;
        wordOffset = dWord;
        if (wordOffset >= 0 && wordOffset < 32 && bitIndex >= 0 && bitIndex < 16)
        {
            writePlcValueBit[wordOffset, bitIndex] = value;
        }
    }

    public static int[] PlcValue = new int[10000];
    public static int[] writePlcValue = new int[10000];
    public static void SetPlc(int strAddress, int strData)
    {
        try
        {
            int address = strAddress;
            string hexValue;

            if (strData <= 0xFFFF) // 16비트
            {
                hexValue = strData.ToString("X4");
                PLCData.writePlcValue[address] = Convert.ToUInt16(hexValue, 16);
            }
            else // 32비트
            {
                hexValue = strData.ToString("X8");
                // 하위 워드 (뒤 4자리)
                PLCData.writePlcValue[address] = Convert.ToUInt16(hexValue.Substring(4, 4), 16);
                // 상위 워드 (앞 4자리)
                PLCData.writePlcValue[address + 1] = Convert.ToUInt16(hexValue.Substring(0, 4), 16);
            }
        }
        catch (Exception ex)
        {
            //Logger.Log("PLC 데이터 변환 오류: " + ex.Message);
        }
    }
