        private void tmrLotorAssembleTimer_Tick(object sender, EventArgs e)
        {
            //tmrStopWatchLotorAssemble
            label7.Text = LotorAssembleStep.ToString("F1");
            if (PLCData.PlcValueBit[0, 2] == true && LotorAssembleStep != 0)
            {
                InitControlBolt();
                LotorAssembleStep = 0;
            }
            switch (LotorAssembleStep)
            {
                case 0:

                    if (PLCData.PlcValueBit[0, 6] == true) //좌측 볼트 조립 제품 감지 센서 받음
                    {
                        boltStartTime = System.DateTime.Now.ToString("HH:mm:ss");
                        LvdtMax = 0;
                        ToolStep = 0;
                        LotorAssembleStep = 1;
                    }
                    break;

                case 1:

                    //Logger.Log($"ToolStep:{ToolStep.ToString()}");
                    if (ToolStep == 0)
                    {
                        if (PLCData.PlcValueBit[0, 8] == false)
                        {
                            if (LvdtMax < ValueLvdt)
                            {
                                LvdtMax = ValueLvdt;
                            }
                            ToolStep = 1;
                        }
                    }
                    else if (ToolStep == 1)
                    {
                        if (LvdtMax < ValueLvdt)
                        {
                            LvdtMax = ValueLvdt;
                        }
                        if (PLCData.PlcValueBit[0, 8] == true)
                        {
                            tmrStopWatch.Restart();
                            ToolStep = 1.1;
                        }
                    }
                    else if (ToolStep == 1.1)
                    {
                        if (LvdtMax < ValueLvdt)
                        {
                            LvdtMax = ValueLvdt;
                        }
                        if (tmrStopWatch.ElapsedMilliseconds > 500)
                        {
                            ToolStep = 2;
                        }
                    }
                    else if (ToolStep == 2)
                    {
                        srcMeasureBolt1.Text = (LvdtMax + GlobalValues.LvdtOffset1).ToString("F2");

                        Random rand = new Random();
                        double randomValue = GlobalValues.RndMin + rand.NextDouble() * (GlobalValues.RndMax - GlobalValues.RndMin);
                        srcMeasureBoltTq1.Text = randomValue.ToString("F2");
                        srcDecBoltTq1.Text = "OK";
                        srcDecBoltTq1.ForeColor = System.Drawing.Color.LightBlue;

                        if (LvdtMax + GlobalValues.LvdtOffset1 <= GlobalValues.BoltLenSpecMax &&
                            LvdtMax + GlobalValues.LvdtOffset1 >= GlobalValues.BoltLenSpecMin)
                        {
                            srcDecBolt1.Text = "OK";
                            srcDecBolt1.ForeColor = System.Drawing.Color.LightBlue;
                            PlaySound("DINGDONG.wav");
                            ToolStep = 0;
                            LotorAssembleStep = 2;
                        }
                        else
                        {
                            srcDecBolt1.Text = "NG";
                            srcDecBolt1.ForeColor = System.Drawing.Color.OrangeRed;
                            PlaySound("NG.wav");
                            LvdtMax = 0;
                            ToolStep = 0;
                        }
                    }
                    break;

                case 2:

                    if (PLCData.PlcValueBit[0, 5] == true) //좌측 볼트 조립 제품 감지 센서 받음
                    {
                        ToolStep = 0;
                        LvdtMax = 0;
                        LotorAssembleStep = 3;
                    }
                    break;

                case 3:

                    //Logger.Log($"ToolStep:{ToolStep.ToString()}");
                    if (ToolStep == 0)
                    {
                        if (PLCData.PlcValueBit[0, 8] == false)
                        {
                            if (LvdtMax < ValueLvdt)
                            {
                                LvdtMax = ValueLvdt;
                            }
                            ToolStep = 1;
                        }
                    }
                    else if (ToolStep == 1)
                    {
                        if (LvdtMax < ValueLvdt)
                        {
                            LvdtMax = ValueLvdt;
                        }
                        if (PLCData.PlcValueBit[0, 8] == true)
                        {
                            tmrStopWatch.Restart();
                            ToolStep = 1.1;
                        }
                    }
                    else if (ToolStep == 1.1)
                    {
                        if (LvdtMax < ValueLvdt)
                        {
                            LvdtMax = ValueLvdt;
                        }
                        if (tmrStopWatch.ElapsedMilliseconds > 500)
                        {
                            ToolStep = 2;
                        }
                    }
                    else if (ToolStep == 2)
                    {
                        srcMeasureBolt2.Text = (LvdtMax + GlobalValues.LvdtOffset2).ToString("F2");
                        Random rand = new Random();
                        double randomValue = GlobalValues.RndMin + rand.NextDouble() * (GlobalValues.RndMax - GlobalValues.RndMin);
                        srcMeasureBoltTq2.Text = randomValue.ToString("F2");
                        srcDecBoltTq2.Text = "OK";
                        srcDecBoltTq2.ForeColor = System.Drawing.Color.LightBlue;

                        if (LvdtMax + GlobalValues.LvdtOffset2 <= GlobalValues.BoltLenSpecMax &&
                            LvdtMax + GlobalValues.LvdtOffset2 >= GlobalValues.BoltLenSpecMin)
                        {
                            srcDecBolt2.Text = "OK";
                            srcDecBolt2.ForeColor = System.Drawing.Color.LightBlue;
                            PlaySound("DINGDONG.wav");
                            ToolStep = 0;
                            LotorAssembleStep = 4;

                            boltStartTime = System.DateTime.Now.ToString("HH:mm:ss");
                            InsertMes_Bolt(System.DateTime.Now.ToString("yyyy-MM-dd"), boltStartTime, boltEndTime,
                                           srcMeasureBoltTq1.Text, srcMeasureBolt1.Text, srcDecBolt1.Text, "",
                                           srcMeasureBoltTq2.Text, srcMeasureBolt2.Text, srcDecBolt2.Text, "", false);
                        }
                        else
                        {
                            srcDecBolt2.Text = "NG";
                            srcDecBolt2.ForeColor = System.Drawing.Color.OrangeRed;
                            PlaySound("NG.wav");
                            LvdtMax = 0;
                            ToolStep = 0;
                        }
                    }
                    break;

                #region === 기존 case 4~10 (주석 보존) ===
                /*
                case 4:
                    if (PLCData.PlcValueBit[0, 4] == true)
                    {
                        LotorStartTime = System.DateTime.Now.ToString("HH:mm:ss");
                        PLCData.SetPlcBit(12, 0~3, false);
                        timeList.Clear(); valueList.Clear(); tmpMax = 0;
                        InitControlBolt(); Logger.Log("작업 시작"); LotorAssembleStep = 5;
                    } break;
                case 5: 로드셀 < 0.1 확인 → 포지션3 이동 → 5.1
                case 5.1: PlcValueBit[14,2] 도착 → 5.2
                case 5.2: 0.5초 대기 → 5.3
                case 5.3: 포지션2 이동 시작 → 6
                case 6: 시간 기반 그래프, 부하 감지, 13 초과→6.1, 서보 도착+0.5초→6.5
                case 6.5: 시간→13mm 스케일링, 그래프 재그리기, 가이드라인, 판정, MES → 7
                case 6.1: NG 수동 원위치 복귀 → 6.2
                case 7: 0.5초 후 포지션1 이동 → 8
                case 8: 포지션1 도착 → 8.1
                case 8.1: NG→재검사(4), OK→9
                case 9: 제품 제거 → OK:10, NG:0
                case 10: 카운트 증가, 저장 → 0
                ※ 상세 코드는 memory/assemble310-steps.md 참조
                */
                #endregion

                // ===== 새 게이지 검사 흐름 (case 4~10) =====

                case 4:
                    if (PLCData.PlcValueBit[0, 4] == true)
                    {
                        LotorStartTime = System.DateTime.Now.ToString("HH:mm:ss");
                        PLCData.SetPlcBit(12, 0, false);
                        PLCData.SetPlcBit(12, 1, false);
                        PLCData.SetPlcBit(12, 2, false);
                        PLCData.SetPlcBit(12, 3, false);

                        timeList.Clear();
                        valueList.Clear();
                        tmpMax = 0;
                        loadStarted = false;
                        InitControlBolt();

                        Logger.Log("작업 시작 - 포지션 3번 이동");
                        PLCData.SetPlcBit(12, 2, true); // 1축 3번 포지션 이동 ON
                        LotorAssembleStep = 4.1;
                    }
                    break;

                case 4.1:
                    if (PLCData.PlcValueBit[14, 2] == true) // 3번 포지션 도착
                    {
                        PLCData.SetPlcBit(12, 2, false);
                        Logger.Log("포지션 3번 도착 완료");
                        LoadStopWatch.Restart();
                        LotorAssembleStep = 4.2;
                    }
                    break;

                case 4.2:
                    if (LoadStopWatch.Elapsed.TotalSeconds > 0.5)
                    {
                        // 로드셀 리셋
                        ResetLoadCell();
                        Logger.Log("로드셀 초기화");
                        tmrStopWatch.Restart();
                        LotorAssembleStep = 4.3;
                    }
                    break;

                case 4.3:
                    if (tmrStopWatch.ElapsedMilliseconds > 500)
                    {
                        // 자동 → 수동 모드 전환
                        PLCData.SetPlcBit(9, 6, true);   // 1축 수동 ON
                        PLCData.SetPlcBit(11, 6, true);  // 2축 수동 ON
                        PLCData.SetPlcBit(9, 5, false);  // 1축 자동 OFF
                        PLCData.SetPlcBit(11, 5, false); // 2축 자동 OFF
                        Logger.Log("수동 모드 전환");
                        LotorAssembleStep = 4.4;
                    }
                    break;

                case 4.4:
                    if (PLCData.PlcValueBit[8, 4] == true &&
                        PLCData.PlcValueBit[8, 3] == false &&
                        PLCData.PlcValueBit[10, 4] == true &&
                        PLCData.PlcValueBit[10, 3] == false)
                    {
                        Logger.Log("수동 모드 확인");
                        LotorAssembleStep = 4.5;
                    }
                    break;

                case 4.5:
                    // 게이지 검사 서보 속도 세팅
                    GlobalValues.FlagServoSet = true;
                    savedJogSpd = GlobalValues.Servo1JogSpd;
                    GlobalValues.Servo1JogSpd = GlobalValues.Servo1GaugeSpd;
                    PLCData.ServoSet();
                    Logger.Log($"게이지 검사 서보 속도 {GlobalValues.Servo1GaugeSpd} 세팅");
                    tmrStopWatch.Restart();
                    LotorAssembleStep = 4.6;
                    break;

                case 4.6:
                    if (tmrStopWatch.ElapsedMilliseconds > 1000)
                    {
                        GlobalValues.FlagServoSet = false;
                        // 그래프 초기화
                        ClassZedGraph.InitGraph(
                            zedGraphControl1,
                            title: "",
                            yTitle: "Value(Kg)",
                            yMin: 0,
                            yMax: 15,
                            rollingWindowSec: 5,
                            pointsCapacity: 3000,
                            clearAll: true,
                            curveColor: System.Drawing.Color.FromArgb(45, 45, 45),
                            lineWidth: 2.0f,
                            xTitle: "Distance (mm)"
                        );
                        ClassZedGraph.AddGuideLines(zedGraphControl1,
                            yLines: new double[] { GlobalValues.SpecLoadSpecMin, GlobalValues.SpecLoadSpecMax },
                            yColor: System.Drawing.Color.Red,
                            lineWidth: 2.0f,
                            lineStyle: System.Drawing.Drawing2D.DashStyle.Dash);

                        PLCData.SetPlcBit(9, 1, true); // 1축 조그 CW(전진)
                        Logger.Log("조그 전진 시작 (게이지 검사)");
                        LotorAssembleStep = 5;
                    }
                    break;

                case 5:
                    // 부하 감지 대기 (그래프 아직 안그림)
                    if (ValueLoadCell > 0.1)
                    {
                        loadStarted = true;
                        gaugeStartValue = ValueGauge;
                        Logger.Log($"부하 감지 - 그래프 시작, LoadCell={ValueLoadCell:F3}, Gauge={ValueGauge:F3}");
                        LotorAssembleStep = 6;
                    }
                    // 부하 미감지 상태에서 게이지 0 도달 → 정지
                    if (Math.Abs(ValueGauge) <= 0.05)
                    {
                        PLCData.SetPlcBit(9, 1, false);
                        Logger.Log("게이지 0 도달 (부하 미감지) - 조그 정지");
                        LotorAssembleStep = 6.5;
                    }
                    break;

                case 6:
                    // 그래프 그리기 + 모니터링
                    {
                        double gaugeX = ValueGauge - gaugeStartValue; // 시작점 대비 이동거리 (양수)
                        timeList.Add(gaugeX);
                        valueList.Add(ValueLoadCell);
                        if (tmpMax < ValueLoadCell) { tmpMax = ValueLoadCell; }

                        ClassZedGraph.DrawGraph(zedGraphControl1, ValueLoadCell, gaugeX);

                        // 게이지 0 도달 → 조그 정지, 판정
                        if (Math.Abs(ValueGauge) <= 0.05)
                        {
                            PLCData.SetPlcBit(9, 1, false);
                            Logger.Log($"게이지 0 도달 - 조그 정지, 최대하중={tmpMax:F3}");
                            LotorAssembleStep = 6.5;
                        }
                        // 하중이 스펙 MAX 초과 → 즉시 정지
                        else if (ValueLoadCell > GlobalValues.SpecLoadSpecMax)
                        {
                            PLCData.SetPlcBit(9, 1, false);
                            Logger.Log($"하중 초과 정지 - LoadCell={ValueLoadCell:F3} > Max={GlobalValues.SpecLoadSpecMax}");
                            LotorAssembleStep = 6.5;
                        }
                    }
                    break;

                case 6.5:
                    // 판정
                    {
                        srcMeasureLoad.Text = tmpMax.ToString("F2");
                        Logger.Log($"판정: 최대하중={tmpMax:F3}, SpecMin={GlobalValues.SpecLoadSpecMin}, SpecMax={GlobalValues.SpecLoadSpecMax}");

                        if (tmpMax >= GlobalValues.SpecLoadSpecMin && tmpMax <= GlobalValues.SpecLoadSpecMax)
                        {
                            srcDecideLoad.Text = "OK";
                            srcDecideLoad.ForeColor = System.Drawing.Color.LightBlue;
                            PlaySound("DINGDONG.wav");
                            Logger.Log("판정 OK");
                        }
                        else
                        {
                            srcDecideLoad.Text = "NG";
                            srcDecideLoad.ForeColor = System.Drawing.Color.OrangeRed;
                            PlaySound("NG.wav");
                            Logger.Log("판정 NG");
                        }

                        LotorEndTime = System.DateTime.Now.ToString("HH:mm:ss");
                        InsertMes_Lotor(System.DateTime.Now.ToString("yyyy-MM-dd"), LotorStartTime, LotorEndTime,
                                        srcMeasureLoad.Text, "", srcDecideLoad.Text, "", false);

                        // 조그 속도 복원
                        GlobalValues.Servo1JogSpd = savedJogSpd;
                        LotorAssembleStep = 7;
                    }
                    break;

                case 7:
                    // 자동 모드 전환
                    PLCData.SetPlcBit(9, 5, true);   // 1축 자동 ON
                    PLCData.SetPlcBit(11, 5, true);  // 2축 자동 ON
                    PLCData.SetPlcBit(9, 6, false);  // 1축 수동 OFF
                    PLCData.SetPlcBit(11, 6, false); // 2축 수동 OFF
                    Logger.Log("자동 모드 전환");
                    tmrStopWatch.Restart();
                    LotorAssembleStep = 7.1;
                    break;

                case 7.1:
                    if (tmrStopWatch.ElapsedMilliseconds > 500)
                    {
                        PLCData.SetPlcBit(12, 0, true); // 1축 1번 포지션 이동 ON
                        Logger.Log("1축 1번 포지션 이동 시작");
                        LotorAssembleStep = 8;
                    }
                    break;

                case 8:
                    if (PLCData.PlcValueBit[14, 0] == true) // 도착 완료
                    {
                        PLCData.SetPlcBit(12, 0, false);
                        Logger.Log("1축 1번 포지션 이동 완료");
                        LotorAssembleStep = 8.1;
                    }
                    break;

                case 8.1:
                    if (srcDecideLoad.Text == "NG")
                    {
                        if (PLCData.PlcValueBit[0, 0] == true)
                        {
                            LotorAssembleStep = 4; // 재검사
                        }
                    }
                    else
                    {
                        LotorAssembleStep = 9;
                    }
                    break;

                case 9:
                    if (PLCData.PlcValueBit[0, 4] == false) // 제품 제거
                    {
                        if (srcDecideLoad.Text == "OK")
                            LotorAssembleStep = 10;
                        else
                            LotorAssembleStep = 0;
                    }
                    break;

                case 10:
                    GlobalValues.TotalCount++;
                    GlobalValues.OkCount++;
                    lbOkCount.Text = GlobalValues.OkCount.ToString();
                    lbNGCount.Text = (GlobalValues.TotalCount - GlobalValues.OkCount).ToString();
                    lbTotalCount.Text = GlobalValues.TotalCount.ToString();
                    GlobalValues.SaveCounts();
                    LotorAssembleStep = 0;
                    break;

                case 99:

                    if (PLCData.PlcValueBit[0, 4] == true)
                    {
                        LotorAssembleStep = 100;
                    }
                    break;

                case 100:

                    tmrStopWatch.Restart();
                    PLCData.SetPlcBit(12, 3, true); // 1축 4번 포지션 이동 ON
                    LotorAssembleStep = 101;
                    Logger.Log("1축 4번 포지션 이동 시작");
                    break;

                case 101:

                    if (tmrStopWatch.ElapsedMilliseconds > 500)
                    {
                        if (PLCData.PlcValueBit[12, 3] == true)
                        {
                            PLCData.SetPlcBit(12, 3, false); // 1축 4번 포지션 이동 OFF
                        }
                    }
                    if (PLCData.PlcValueBit[14, 3] == true)// 1축 4번 포지션 도착 완료
                    {
                        PLCData.SetPlcBit(12, 3, false); // 1축 4번 포지션 이동 Off
                        Logger.Log("1축 4번 포지션 도착 완료");
                        LotorAssembleStep = 102;
                    }
                    break;

                case 102:

                    tmrFlikerTimer.Stop();
                    PLCData.SetPlcBit(9, 6, true); //1축 수동 ON
                    PLCData.SetPlcBit(11, 6, true); //2축 수동 ON
                    PLCData.SetPlcBit(9, 5, false); //1축 자동 OFF
                    PLCData.SetPlcBit(11, 5, false); //2축 자동 OFF
                                                     //PLCData.SetPlc(5002, GlobalValues.Servo1JogSpd/2); //조그 속도 기존의 반으로
                    LotorAssembleStep = 103;
                    Logger.Log("마스터 측정 시작");
                    break;

                case 103:

                    if (PLCData.PlcValueBit[8, 4] == true &&
                        PLCData.PlcValueBit[8, 3] == false &&
                        PLCData.PlcValueBit[10, 4] == true &&
                        PLCData.PlcValueBit[10, 3] == false)
                    {
                        Logger.Log("수동 모드 확인");
                        LotorAssembleStep = 104;
                    }
                    break;

                case 104:

                    GlobalValues.FlagServoSet = true;
                    GlobalValues.Servo1JogSpd = 200;
                    PLCData.ServoSet();
                    Logger.Log("조그 속도 200 세팅 지령");
                    LotorAssembleStep = 105;
                    break;

                case 105:

                    tmrFlikerTimer.Start();
                    tmrStopWatch.Restart();
                    LotorAssembleStep = 105.1;
                    break;

                case 105.1:

                    if (tmrStopWatch.ElapsedMilliseconds > 1000)
                    {
                        Logger.Log("조그 속도 200 세팅 확인");
                        GlobalValues.FlagServoSet = false;
                        PLCData.SetPlcBit(9, 1, true); //1축 조그 전진
                        Logger.Log("조그 전진 시작");
                        LotorAssembleStep = 106;
                    }
                    break;

                case 106:

                    if (ValueLoadCell > 5)
                    {
                        Logger.Log("조그 전진 정지");
                        PLCData.SetPlcBit(9, 1, false); //1축 조그 전진 OFF                        
                        tmrStopWatch.Restart();
                        LotorAssembleStep = 107;
                    }

                    break;

                case 107:

                    GlobalValues.FlagServoSet = true;
                    tmrStopWatch.Restart();
                    LotorAssembleStep = 108;
                    break;

                case 108:

                    if (tmrStopWatch.ElapsedMilliseconds > 1000)
                    {
                        Logger.Log("현재 토크 : " + ValueLoadCell.ToString());
                        Logger.Log("현재 위치 : " + PLCData.PlcValue[5000].ToString());
                        LotorAssembleStep = 109;
                    }
                    break;

                case 109:

                    Logger.Log("마스터 지그 측정 완료");
                    Logger.Log("기존 마스터(포지션3) 좌표 : " + GlobalValues.Servo1Pos3.ToString());
                    GlobalValues.Servo1Pos3 = PLCData.PlcValue[5000];
                    Logger.Log("변경 마스터(포지션3) 좌표 : " + GlobalValues.Servo1Pos3.ToString());

                    //- 서보 1 : 10000 -> 5mm(2000->1mm)
                    //GlobalValues.Servo1Pos3.ToString() - (13mm * 2000)

                    Logger.Log("기존 조립(포지션2) 좌표 : " + GlobalValues.Servo1Pos2.ToString());
                    //GlobalValues.Servo1Pos2 = PLCData.PlcValue[5000] - (13 * 2000);
                    GlobalValues.Servo1Pos2 = PLCData.PlcValue[5000];
                    Logger.Log("변경 좌표(포지션2) 좌표 (마스터)");
                    Logger.Log($":" + GlobalValues.Servo1Pos2.ToString());
                    GlobalValues.SaveChannelSettingsToIni();
                    GlobalValues.FlagServoSet = false;
                    LotorAssembleStep = 110;
                    break;

                case 110:

                    GlobalValues.Servo1JogSpd = 10000;
                    GlobalValues.LoadSettingsFromIni();
                    Logger.Log("데이터 저장 완료");
                    tmrStopWatch.Restart();

                    InsertMes_Lotor_Master(System.DateTime.Now.ToString("yyyy-MM-dd"), MasterStartTime, System.DateTime.Now.ToString("HH:mm:ss"),
                        "", "", "", "", true);

                    LotorAssembleStep = 111;
                    break;

                case 111:

                    if (PLCData.PlcValueBit[8, 1] == true || PLCData.PlcValueBit[10, 1] == true) // 알람이 떠 있으면 
                    {

                    }
                    else
                    {
                        LotorAssembleStep = 112;
                    }
                    break;

                case 112:

                    PLCData.SetPlcBit(9, 5, true); //1축 자동 ON
                    PLCData.SetPlcBit(11, 5, true); //2축 자동 ON
                    PLCData.SetPlcBit(9, 6, false); //1축 수동 OFF
                    PLCData.SetPlcBit(11, 6, false); //2축 수동 OFF                    
                    LotorAssembleStep = 103;
                    Logger.Log("자동 전환");
                    LotorAssembleStep = 113;
                    break;

                case 113:

                    tmrStopWatch.Restart();
                    PLCData.SetPlcBit(12, 0, true); // 1축 1번 포지션 이동 ON
                    LotorAssembleStep = 114;
                    Logger.Log("1축 1번 포지션 이동 시작");
                    break;

                case 114:

                    if (tmrStopWatch.ElapsedMilliseconds > 500)
                    {
                        if (PLCData.PlcValueBit[12, 0] == true)
                        {
                            PLCData.SetPlcBit(12, 0, false); // 1축 0번 포지션 이동 OFF
                        }
                    }
                    if (PLCData.PlcValueBit[14, 0] == true)// 1축 1번 포지션 도착 완료
                    {
                        Logger.Log("1축 1번 포지션 도착 완료");
                        LotorAssembleStep = 115;
                    }
                    break;

                case 115:

                    if (PLCData.PlcValueBit[0, 4] == false)
                    {
                        Logger.Log("마스터 제거 확인");
                        LotorAssembleStep = 0;
                    }
                    break;


            }
        }
        private void tmrLotorFeederTimer_Tick(object sender, EventArgs e)
        {
            switch (LotorFeederStep)
            {

                case 0:
                    if (FlagFeederRun == true)
                    {
                        Logger.Log("피더 공급 시작");
                        PLCData.SetPlcBit(4, 13, true); //로터 전진 신호 ON
                        FlagServoRunReady = false;
                        LotorFeederStep = 1;
                    }
                    break;

                case 1:
                    if (PLCData.PlcValueBit[1, 3] == true) //로터 감지 센서 받으면
                    {
                        Logger.Log("로터 감지됨");
                        tmrStopWatchLotorFeeder.Restart();
                        LotorFeederStep = 2;
                    }
                    break;

                case 2:

                    if (tmrStopWatchLotorFeeder.ElapsedMilliseconds >= 500)  //로터 감지 센서 받고 1초 후
                    {
                        Logger.Log("로터 공급 정지");
                        PLCData.SetPlcBit(4, 13, false); //로터 전진 신호 OFF
                        FlagFeederRun = false;
                        FlagServoRunReady = true;
                        LotorFeederStep = 0;
                    }
                    break;
            }


        }
        private bool isIvProcessing = false;
        private void tmrLotorServoTimer_Tick(object sender, EventArgs e)
        {
            label5.Text = $"ServoStep:[{LotorServoStep}] FeederStep:[{LotorFeederStep}] BoltStep:[{LotorAssembleStep}]";

            switch (LotorServoStep)
            {
                case 0:
                    if (FlagServoRunReady && PLCData.PlcValueBit[0, 10])
                    {
                        Logger.Log("인덱스 서보 동작 시작(90도)");
                        LotorServoStep = 1;
                    }
                    break;

                case 1:
                    PLCData.SetPlcBit(13, 1, true); // 서보 회전 지령 ON
                    LotorServoStep = 2;
                    break;

                case 2:
                    if (PLCData.PlcValueBit[15, 1]) // 회전 완료
                    {
                        PLCData.SetPlcBit(13, 1, false); // 지령 OFF
                        LotorServoStep = 3;
                    }
                    break;

                case 3:
                    PLCData.SetPlcBit(4, 10, true); // 비전 트리거 ON
                    LotorServoStep = 4;
                    break;

                case 4:
                    PLCData.SetPlcBit(5, 3, true); // 디스펜서 트리거 ON
                    LotorServoStep = 5;
                    break;

                case 5:
                    if (!isIvProcessing)
                    {
                        isIvProcessing = true;
                        if (CheckAndBackupIvImages())
                        {
                            LotorServoStep = 6;
                            isIvProcessing = false;
                            InsertMes_Grs(System.DateTime.Now.ToString("yyyy-MM-dd"),
                                          System.DateTime.Now.ToString("HH:mm:ss"), System.DateTime.Now.ToString("HH:mm:ss"),
                                          tmpDec, tmpLot, tmpDec);
                        }
                    }
                    break;

                case 6:
                    PLCData.SetPlcBit(4, 10, false); // 비전 트리거 OFF
                    PLCData.SetPlcBit(5, 3, false); // 디스펜서 트리거 OFF
                    LotorServoStep = 7;
                    break;

                case 7:
                    Logger.Log("인덱스 서보 동작 종료(90도)");

                    // 스테이지 순환
                    currentStageIndex = (currentStageIndex + 1) % 4;
                    StageHasProduct[currentStageIndex] = PLCData.PlcValueBit[1, 3];

                    string status = StageHasProduct[currentStageIndex] ? "제품 있음" : "제품 없음";
                    Logger.Log($"[{currentStageIndex}번 스테이지] 상태: {status}");

                    LotorServoStep = 8;
                    break;

                case 8:
                    if (!PLCData.PlcValueBit[1, 3]) // 로터 감지 안됨
                    {
                        Logger.Log("로터 감지 안됨. 피더 공급 시작");
                        FlagServoRunReady = false;
                        FlagFeederRun = true;
                        LotorServoStep = 0;
                    }
                    break;
            }
        }
