        public void InsertMes2(string part_no, string part_name, string serial_no, string end_serial, string work_date,
                                 TimeSpan work_start_time,
            TimeSpan work_end_time,
            string grease_decision,
            decimal rotor_press,
            decimal rotor_length,
            string rotor_decision,
            decimal mscrew_torque1,
            decimal mscrew_length1,
            string mscrew_decision1,
            decimal mscrew_torque2,
            decimal mscrew_length2,
            string mscrew_decision2
)
        {

            try
            {
                using (var conn = new OleDbConnection(GlobalValues.gConString_MES))
                {
                    conn.Open();

                    string query = @"
                INSERT INTO MOTOR_ROTOR_SUB_ASSY_310
                (
                    part_no,
                    part_name,
                    serial_no,
                    end_serial,
                    work_date,
                    work_start_time,
                    work_end_time,
                    grease_decision,
                    rotor_press,
                    rotor_length,
                    rotor_decision,
                    mscrew_torque1,
                    mscrew_length1,
                    mscrew_decision1,
                    mscrew_torque2,
                    mscrew_length2,
                    mscrew_decision2
                )
                VALUES
                (
                    ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?
                )";

                    using (var cmd = new OleDbCommand(query, conn))
                    {
                        cmd.Parameters.AddWithValue("@p1", part_no ?? (object)DBNull.Value);
                        cmd.Parameters.AddWithValue("@p2", part_name ?? (object)DBNull.Value);
                        cmd.Parameters.AddWithValue("@p3", serial_no ?? (object)DBNull.Value);
                        cmd.Parameters.AddWithValue("@p4", end_serial ?? (object)DBNull.Value);
                        cmd.Parameters.AddWithValue("@p5", work_date ?? (object)DBNull.Value);
                        cmd.Parameters.AddWithValue("@p6", work_start_time.ToString(@"hh\:mm\:ss"));
                        cmd.Parameters.AddWithValue("@p7", work_end_time.ToString(@"hh\:mm\:ss"));
                        cmd.Parameters.AddWithValue("@p8", grease_decision ?? (object)DBNull.Value);
                        cmd.Parameters.AddWithValue("@p9", rotor_press);
