                        Logger.Log("현재 위치 : " + PLCData.PlcValue[5000].ToString());
                        LotorAssembleStep = 109;
                    }
                    break;

                case 109:

                    Logger.Log("마스터 지그 측정 완료");
                    Logger.Log("기존 마스터(포지션3) 좌표 : " + GlobalValues.Servo1Pos3.ToString());
                    GlobalValues.Servo1Pos3 = PLCData.PlcValue[5000];
                    Logger.Log("변경 마스터(포지션3) 좌표 : " + GlobalValues.Servo1Pos3.ToString());

                    //- 서보 1 : 10000 -> 5mm(2000->1mm)
                    //GlobalValues.Servo1Pos3.ToString() - (13mm * 2000)

                    Logger.Log("기존 조립(포지션2) 좌표 : " + GlobalValues.Servo1Pos2.ToString());
                    //GlobalValues.Servo1Pos2 = PLCData.PlcValue[5000] - (13 * 2000);
                    GlobalValues.Servo1Pos2 = PLCData.PlcValue[5000];
                    Logger.Log("변경 좌표(포지션2) 좌표 (마스터)");
                    Logger.Log($":" + GlobalValues.Servo1Pos2.ToString());
                    GlobalValues.SaveChannelSettingsToIni();
                    GlobalValues.FlagServoSet = false;
                    LotorAssembleStep = 110;
                    break;

                case 110:

                    GlobalValues.Servo1JogSpd = 10000;
                    GlobalValues.LoadSettingsFromIni();
                    Logger.Log("데이터 저장 완료");
                    tmrStopWatch.Restart();

                    InsertMes_Lotor_Master(System.DateTime.Now.ToString("yyyy-MM-dd"), MasterStartTime, System.DateTime.Now.ToString("HH:mm:ss"),
                        "", "", "", "", true);

                    LotorAssembleStep = 111;
                    break;

                case 111:

                    if (PLCData.PlcValueBit[8, 1] == true || PLCData.PlcValueBit[10, 1] == true) // 알람이 떠 있으면 
                    {

                    }
                    else
                    {
                        LotorAssembleStep = 112;
                    }
                    break;

                case 112:

                    PLCData.SetPlcBit(9, 5, true); //1축 자동 ON
                    PLCData.SetPlcBit(11, 5, true); //2축 자동 ON
                    PLCData.SetPlcBit(9, 6, false); //1축 수동 OFF
                    PLCData.SetPlcBit(11, 6, false); //2축 수동 OFF                    
                    LotorAssembleStep = 103;
                    Logger.Log("자동 전환");
                    LotorAssembleStep = 113;
                    break;

                case 113:

                    tmrStopWatch.Restart();
                    PLCData.SetPlcBit(12, 0, true); // 1축 1번 포지션 이동 ON
                    LotorAssembleStep = 114;
                    Logger.Log("1축 1번 포지션 이동 시작");
                    break;

                case 114:

                    if (tmrStopWatch.ElapsedMilliseconds > 500)
                    {
                        if (PLCData.PlcValueBit[12, 0] == true)
                        {
                            PLCData.SetPlcBit(12, 0, false); // 1축 0번 포지션 이동 OFF
                        }
