        private bool isIvProcessing = false;
        private void tmrLotorServoTimer_Tick(object sender, EventArgs e)
        {
            label5.Text = $"ServoStep:[{LotorServoStep}] FeederStep:[{LotorFeederStep}] BoltStep:[{LotorAssembleStep}]";

            switch (LotorServoStep)
            {
                case 0:
                    if (FlagServoRunReady && PLCData.PlcValueBit[0, 10])
                    {
                        Logger.Log("인덱스 서보 동작 시작(90도)");
                        LotorServoStep = 1;
                    }
                    break;

                case 1:
                    PLCData.SetPlcBit(13, 1, true); // 서보 회전 지령 ON
                    LotorServoStep = 2;
                    break;

                case 2:
                    if (PLCData.PlcValueBit[15, 1]) // 회전 완료
                    {
                        PLCData.SetPlcBit(13, 1, false); // 지령 OFF
                        LotorServoStep = 3;
                    }
                    break;

                case 3:
                    PLCData.SetPlcBit(4, 10, true); // 비전 트리거 ON
                    LotorServoStep = 4;
                    break;

                case 4:
                    PLCData.SetPlcBit(5, 3, true); // 디스펜서 트리거 ON
                    LotorServoStep = 5;
                    break;

                case 5:
                    if (!isIvProcessing)
                    {
                        isIvProcessing = true;
                        if (CheckAndBackupIvImages())
                        {
                            LotorServoStep = 6;
                            isIvProcessing = false;
                            InsertMes_Grs(System.DateTime.Now.ToString("yyyy-MM-dd"),
                                          System.DateTime.Now.ToString("HH:mm:ss"), System.DateTime.Now.ToString("HH:mm:ss"),
                                          tmpDec, tmpLot, tmpDec);
                        }
                    }
                    break;

                case 6:
                    PLCData.SetPlcBit(4, 10, false); // 비전 트리거 OFF
                    PLCData.SetPlcBit(5, 3, false); // 디스펜서 트리거 OFF
                    LotorServoStep = 7;
                    break;

                case 7:
                    Logger.Log("인덱스 서보 동작 종료(90도)");

                    // 스테이지 순환
                    currentStageIndex = (currentStageIndex + 1) % 4;
                    StageHasProduct[currentStageIndex] = PLCData.PlcValueBit[1, 3];

                    string status = StageHasProduct[currentStageIndex] ? "제품 있음" : "제품 없음";
                    Logger.Log($"[{currentStageIndex}번 스테이지] 상태: {status}");

                    LotorServoStep = 8;
                    break;

                case 8:
                    if (!PLCData.PlcValueBit[1, 3]) // 로터 감지 안됨
                    {
                        Logger.Log("로터 감지 안됨. 피더 공급 시작");
                        FlagServoRunReady = false;
                        FlagFeederRun = true;
                        LotorServoStep = 0;
                    }
                    break;
            }
        }
