        private void SerialRetryTimer_Tick(object sender, EventArgs e)
        {
            if (SerialLoadCell.IsOpen == true)
            {
                RequestLoadCell();
            }

            if (SerialLvdt.IsOpen == true)
            {
                if (FlagLvdtReset == false)
                {
                    if (RequestReady_Lvdt)
                    {
                        RequestLvdt();
                    }
                }
                else
                {
                    ResetLvdt();
                    FlagLvdtReset = false;
                }

                // 리셋 확인 로직
                if (WaitingResetVerify)
                {
                    if (Math.Abs(ValueLoadCell) < 0.001)
                    {
                        Logger.Log("[리셋 성공] 로드셀 값 0.0 확인됨");
                        WaitingResetVerify = false;
                    }
                    else
                    {
                        ResetVerifyCounter++;
                        Logger.Log($"[리셋 대기] {ResetVerifyCounter}회 - 현재값: {ValueLoadCell:F3}");

                        if (ResetVerifyCounter >= MaxResetVerifyRetry)
                        {
                            Logger.Log("[리셋 실패] 로드셀 값 0이 아님 → 수동 확인 필요");
                            WaitingResetVerify = false;
                        }
                    }
                }
            }


