        private decimal GetRandomDecimal(decimal min, decimal max)
        {
            Random rnd = new Random();
            double range = (double)(max - min);
            double sample = rnd.NextDouble();
            decimal result = min + (decimal)(sample * range);
            return Math.Round(result, 5);
        }

