                        else
                        {
                            srcDecBolt1.Text = "NG";
                            srcDecBolt1.ForeColor = System.Drawing.Color.OrangeRed;
                            PlaySound("NG.wav");
                            LvdtMax = 0;
                            ToolStep = 0;
